import { Component, EventEmitter, Output } from '@angular/core';
import { Router } from '@angular/router';

@Component({
  selector: 'app-sidebar',
  templateUrl: './sidebar.component.html',
  styleUrls: ['./sidebar.component.css']
})
export class SidebarComponent {
  @Output() newPostClicked = new EventEmitter<void>();
  constructor(private router: Router) {}
  logout() { this.router.navigate(['/']); }
  openNewPost() {
    // If there's a listener (home page), emit to it
    // Otherwise navigate to home
    if (this.newPostClicked.observers.length > 0) {
      this.newPostClicked.emit();
    } else {
      this.router.navigate(['/home']);
    }
  }
}
<aside class="sidebar-left">
  <!-- User Profile on Top -->
  <div class="user-profile-top mb-4 d-flex align-items-center justify-content-between px-2">
    <div class="d-flex align-items-center gap-2">
      <div class="avatar-circle-sm bg-primary d-flex align-items-center justify-content-center flex-shrink-0">
        <span class="text-white fw-bold">@</span>
      </div>
      <div>
        <div class="fw-bold small text-dark" style="white-space:nowrap;overflow:hidden;text-overflow:ellipsis;max-width:130px;">sourav06.bsky.social</div>
        <div class="text-muted" style="font-size:0.75rem;">@sourav06.bsky.so...</div>
      </div>
    </div>
    <button class="btn btn-link p-0 text-muted">···</button>
  </div>

  <!-- Nav Links -->
  <nav class="flex-grow-1">
    <a class="nav-item" routerLink="/home" routerLinkActive="active" [routerLinkActiveOptions]="{exact:true}">
      <span class="nav-icon">🏠</span><span class="nav-label">Home</span>
    </a>
    <a class="nav-item" routerLink="/explore" routerLinkActive="active">
      <span class="nav-icon">🔍</span><span class="nav-label">Explore</span>
    </a>
    <a class="nav-item" routerLink="/notifications" routerLinkActive="active">
      <span class="nav-icon">🔔</span><span class="nav-label">Notifications</span>
    </a>

    <a class="nav-item">
      <span class="nav-icon">#</span><span class="nav-label">Feeds</span>
    </a>

    <a class="nav-item" routerLink="/follow" routerLinkActive="active">
      <span class="nav-icon">👥</span><span class="nav-label"></span>
    </a>
    <a class="nav-item" routerLink="/profile" routerLinkActive="active">
      <span class="nav-icon">👤</span><span class="nav-label">Profile</span>
    </a>
    <a class="nav-item" routerLink="/settings" routerLinkActive="active">
      <span class="nav-icon">⚙️</span><span class="nav-label">Settings</span>
    </a>
  </nav>

  <!-- New Post Button -->
  <button class="btn btn-primary rounded-pill fw-semibold mt-3 new-post-btn" (click)="openNewPost()">
    ✏️ New Post
  </button>
</aside>
